export interface VocabWord {
  italian: string;
  english: string;
  example: string;
  exampleTranslation: string;
  category: string;
}

export interface GrammarPoint {
  title: string;
  explanation: string;
  examples: { italian: string; english: string }[];
}

export interface Dialogue {
  title: string;
  context: string;
  lines: { speaker: string; italian: string; english: string }[];
}

export interface Exercise {
  type: "mcq" | "fill-blank" | "matching" | "reorder" | "translate";
  question: string;
  options?: string[];
  answer: string;
  pairs?: { left: string; right: string }[];
}

export interface Chapter {
  id: string;
  title: string;
  titleIt: string;
  description: string;
  icon: string;
  vocabulary: VocabWord[];
  grammar: GrammarPoint[];
  dialogue: Dialogue;
  exercises: Exercise[];
}

export interface Level {
  id: string;
  name: string;
  label: string;
  description: string;
  color: string;
  chapters: Chapter[];
}

// Helper to create a chapter quickly
function ch(id: string, title: string, titleIt: string, desc: string, icon: string, vocabulary: VocabWord[], grammar: GrammarPoint[], dialogue: Dialogue, exercises: Exercise[]): Chapter {
  return { id, title, titleIt, description: desc, icon, vocabulary, grammar, dialogue, exercises };
}

